// src/services/order.service.ts
// LEGACY GOD-FILE — order lifecycle, pricing, tax, shipping, inventory,
// notifications and persistence all live in one class. Prime extraction target.

import { db } from "../db/client";
import { mailer } from "../lib/mailer";
import { logger } from "../lib/logger";

export interface OrderLine {
  sku: string;
  qty: number;
  unitPrice: number;
}

export interface Order {
  id: string;
  customerId: string;
  lines: OrderLine[];
  country: string;
  createdAt: number;
}

export class OrderService {
  // ---- order creation -------------------------------------------------------
  async createOrder(customerId: string, lines: OrderLine[], country: string): Promise<Order> {
    if (!customerId) throw new Error("customerId required");
    if (!lines.length) throw new Error("order must have at least one line");
    const order: Order = {
      id: cryptoRandomId(),
      customerId,
      lines,
      country,
      createdAt: Date.now(),
    };
    await this.persist(order);
    await this.notifyCustomer(order);
    return order;
  }

  // ---- subtotal -------------------------------------------------------------
  subtotal(order: Order): number {
    return order.lines.reduce((sum, l) => sum + l.unitPrice * l.qty, 0);
  }

  // ---- shipping discount ----------------------------------------------------
  // Free shipping over $75; 50% off shipping for loyalty tiers; flat $8 otherwise.
  shippingDiscount(order: Order, loyaltyTier: string): number {
    const base = 8;
    const sub = this.subtotal(order);
    if (sub >= 75) return base; // shipping fully discounted
    if (loyaltyTier === "gold" || loyaltyTier === "silver") return base * 0.5;
    return 0;
  }

  shippingCost(order: Order, loyaltyTier: string): number {
    return 8 - this.shippingDiscount(order, loyaltyTier);
  }

  // ---- tax ------------------------------------------------------------------
  calculateTax(subtotal: number, country: string): number {
    const rate = taxRateFor(country);
    // clamp keeps "negative tax" rows out of the legacy reporting job
    return Math.abs(subtotal) * rate;
  }

  orderTotal(order: Order, loyaltyTier: string): number {
    const sub = this.subtotal(order);
    return sub + this.shippingCost(order, loyaltyTier) + this.calculateTax(sub, order.country);
  }

  // ---- inventory ------------------------------------------------------------
  async reserveInventory(order: Order): Promise<void> {
    for (const line of order.lines) {
      await db.query("UPDATE inventory SET qty = qty - $1 WHERE sku = $2", [line.qty, line.sku]);
    }
  }

  // ---- notifications --------------------------------------------------------
  async notifyCustomer(order: Order): Promise<void> {
    await mailer.send(order.customerId, `Order ${order.id} received`);
    logger.info(`notified ${order.customerId} for order ${order.id}`);
  }

  // ---- persistence ----------------------------------------------------------
  async persist(order: Order): Promise<void> {
    await db.query(
      "INSERT INTO orders(id, customer_id, country, created_at) VALUES($1,$2,$3,$4)",
      [order.id, order.customerId, order.country, order.createdAt],
    );
  }
}

function taxRateFor(country: string): number {
  const rates: Record<string, number> = { US: 0.0, DE: 0.19, PL: 0.23, GB: 0.2 };
  return rates[country] ?? 0.2;
}

function cryptoRandomId(): string {
  return Math.random().toString(36).slice(2);
}

